const esbuild = require('esbuild');
const path = require('path');

const isWatch = process.argv.includes('--watch');

/** @type {esbuild.BuildOptions} */
const extConfig = {
  entryPoints: ['src/extension.ts'],
  bundle: true,
  platform: 'node',
  target: 'node18',
  format: 'cjs',
  outfile: 'dist/extension.js',
  external: ['vscode'],
  sourcemap: true,
  minify: false,
  metafile: true,
};

/** @type {esbuild.BuildOptions} */
const webviewConfig = {
  entryPoints: ['media/sidebar.tsx'],
  bundle: true,
  platform: 'browser',
  target: 'es2020',
  format: 'iife',
  outfile: 'media/sidebar.js',
  sourcemap: true,
  minify: false,
  metafile: true,
};

async function build() {
  try {
    const results = await Promise.all([
      esbuild.build(extConfig),
      esbuild.build(webviewConfig),
    ]);
    if (!isWatch) {
      for (const r of results) {
        console.log(await esbuild.analyzeMetafile(r.metafile));
      }
    }
    console.log('Build succeeded.');
  } catch (e) {
    console.error('Build failed:', e);
    process.exit(1);
  }
}

if (isWatch) {
  const ctxExt = await esbuild.context(extConfig);
  const ctxWebview = await esbuild.context(webviewConfig);
  await Promise.all([ctxExt.watch(), ctxWebview.watch()]);
  console.log('Watching for changes...');
} else {
  build();
}

import eslint from '@eslint/js';
import tseslint from 'typescript-eslint';

export default tseslint.config(
  eslint.configs.recommended,
  ...tseslint.configs.recommended,
  {
    rules: {
      '@typescript-eslint/no-unused-vars': ['error', { argsIgnorePattern: '^_' }],
      '@typescript-eslint/no-non-null-assertion': 'off',
      '@typescript-eslint/no-explicit-any': 'off',
      'no-console': 'off',
    },
  },
  {
    ignores: ['out/**', 'dist/**', 'media/sidebar.js', 'node_modules/**'],
  }
);

