  let changed = false;
  for (const [model, injection] of Object.entries(seeds)) {
    if (!(model in injections)) {
      injections[model] = injection;
      changed = true;
    }
  }
  if (changed) {
    globalState.update('modelInjections', injections);
  }
}

/** 根据模型判断是否为 nano-banana 系列 */
export function isNanoBanana(model: string): boolean {
  return model.startsWith('nano-banana');
}

/** 根据模型判断是否为 gpt-image-2-vip */
export function isGptImage2Vip(model: string): boolean {
  return model === 'gpt-image-2-vip';
}

// Markdown 解析与参考图提取

import * as fs from 'fs';
import * as path from 'path';
import { isImageExt, mimeFromExt } from './shared';

export interface ParsedMarkdown {
  /** 替换后的正文 */
  body: string;
  /** 参考图数组（base64 data URI） */
  images: string[];
  /** 图片路径→编号映射 */
  imageMap: Map<string, number>;
}

/**
 * 解析 Markdown：
 * - 匹配 ![alt](路径) 或 ![alt](<路径>) 格式
 * - 相对路径基于 mdDir 解析
 * - 按首次出现顺序去重编号
 * - 正文中替换为 [imageN](文件名去扩展名)
 */
export function parseMarkdown(mdContent: string, mdDir: string): ParsedMarkdown {
  const imageMap = new Map<string, number>();
  const imagePaths: string[] = [];
  let nextIndex = 1;
  const failures: string[] = [];

  // 匹配 ![alt](path) 或 ![alt](<path>) — 尖括号内可含空格与半角括号
  const imgRegex = /!\[([^\]]*)\]\(<?([^)>]+?)>?\)/g;

  let body = mdContent.replace(imgRegex, (fullMatch, _alt: string, rawPath: string) => {
    const imgPath = rawPath.trim();
    let index: number;
    if (imageMap.has(imgPath)) {
      index = imageMap.get(imgPath)!;
    } else {
      const absPath = path.isAbsolute(imgPath) ? imgPath : path.resolve(mdDir, imgPath);
      try {
        const buf = fs.readFileSync(absPath);
        const ext = path.extname(absPath).slice(1);
        const mime = mimeFromExt(ext);
        const dataUri = `data:${mime};base64,${buf.toString('base64')}`;
        index = nextIndex++;
        imageMap.set(imgPath, index);
        imagePaths.push(dataUri);
      } catch {
        failures.push(imgPath);
        return fullMatch; // 保留原文，等后续报错
      }
    }
    const baseName = path.basename(imgPath, path.extname(imgPath));
    return `[image${index}](${baseName})`;
  });

  if (failures.length > 0) {
    throw new Error(`以下参考图读取失败：\n${failures.join('\n')}`);
  }

  return { body, images: imagePaths, imageMap };
}

/**
 * 拼接最终 prompt：模型注入句 + IMAGES.md 全文 + 替换后正文，空行连接，空段省略
 */
export function buildFinalPrompt(
  originalBody: string,
  injection: string,
  imagesMdContent: string | null,
): string {
  const parts: string[] = [];
  if (injection.trim()) parts.push(injection.trim());
  if (imagesMdContent && imagesMdContent.trim()) parts.push(imagesMdContent.trim());
  if (originalBody.trim()) parts.push(originalBody.trim());
  return parts.join('\n\n');
}

// Grsai API 调用层

import * as vscode from 'vscode';
import { isNanoBanana, isGptImage2Vip } from './config';
import { vipPixelSize, GenerateResponse, ResultResponse } from './shared';

const TIMEOUT_MS = 30_000;

async function fetchWithTimeout(url: string, options: RequestInit, timeoutMs = TIMEOUT_MS): Promise<Response> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeoutMs);
  try {
    const resp = await fetch(url, { ...options, signal: controller.signal });
    return resp;
  } finally {
    clearTimeout(timer);
  }
}

/** POST /v1/api/generate 提交生成任务 */
export async function submitGenerate(
  baseUrl: string,
  apiKey: string,
  model: string,
  prompt: string,
  images: string[],
  aspectRatio: string,
  imageSize: string,
): Promise<GenerateResponse> {
  const body: Record<string, unknown> = {
    model,
    prompt,
    images,
    replyType: 'async',
  };

  if (isNanoBanana(model)) {
    body.aspectRatio = aspectRatio;
    body.imageSize = imageSize;
  } else if (isGptImage2Vip(model)) {
    body.aspectRatio = vipPixelSize(aspectRatio, imageSize);
  } else {
    // gpt-image-2 (非 vip)
    body.aspectRatio = aspectRatio;
  }

  const url = `${baseUrl}/v1/api/generate`;
  const resp = await fetchWithTimeout(url, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${apiKey}`,
    },
    body: JSON.stringify(body),
  });

  const json: unknown = await resp.json().catch(() => null);
  if (!resp.ok) {
    throw new Error(`HTTP ${resp.status}: ${JSON.stringify(json)}`);
  }

  return validateGenerateResponse(json);
}

/** GET /v1/api/result?id= 查询任务结果 */
export async function queryResult(baseUrl: string, apiKey: string, jobId: string): Promise<ResultResponse> {
  const url = `${baseUrl}/v1/api/result?id=${encodeURIComponent(jobId)}`;
  const resp = await fetchWithTimeout(url, {
    method: 'GET',
    headers: { Authorization: `Bearer ${apiKey}` },
  });

  const json: unknown = await resp.json().catch(() => null);

  if (!resp.ok) {
    if (resp.status >= 500 || resp.status === 429) {
      throw new Error(`HTTP ${resp.status} — 瞬时错误`);
    }
    throw new Error(`HTTP ${resp.status}: ${JSON.stringify(json)}`);
  }

  return validateResultResponse(json);
}

/** 运行时校验 generate 返回 */
function validateGenerateResponse(json: unknown): GenerateResponse {
  if (!json || typeof json !== 'object') {
    throw new Error('无效的 API 响应（非对象）');
  }
  const r = json as Record<string, unknown>;
  const status = r.status;
  if (status === 'failed' || status === 'violation') {
    throw new Error(`API 返回失败: ${r.error ?? status}`);
  }
  if (status === 'succeeded' || status === 'running') {
    const id = r.id;
    if (!id || typeof id !== 'string') {
      throw new Error('API 返回缺少有效 id');
    }
    return {
      id,
      status: status,
      results: Array.isArray(r.results) ? r.results as { url: string }[] : undefined,
      progress: typeof r.progress === 'number' ? r.progress : undefined,
    };
  }
  throw new Error(`未知 API 状态: ${status}`);
}

/** 运行时校验 result 返回 */
function validateResultResponse(json: unknown): ResultResponse {
  if (!json || typeof json !== 'object') {
    throw new Error('无效的 API 响应（非对象）');
  }
  const r = json as Record<string, unknown>;
  const status = r.status;
  if (!status || typeof status !== 'string') {
    throw new Error('响应缺少 status 字段');
  }
  return {
    id: typeof r.id === 'string' ? r.id : undefined,
    status,
    results: Array.isArray(r.results) ? r.results as { url: string }[] : undefined,
    progress: typeof r.progress === 'number' ? r.progress : undefined,
    error: typeof r.error === 'string' ? r.error : undefined,
  };
}

/** 下载图片到本地 */
export async function downloadImage(url: string, destPath: string): Promise<void> {
  const resp = await fetchWithTimeout(url, {}, TIMEOUT_MS);
  if (!resp.ok) {
    throw new Error(`下载失败 HTTP ${resp.status}: ${url}`);
  }
  const buf = Buffer.from(await resp.arrayBuffer());
  const fs = await import('fs');
  fs.writeFileSync(destPath, buf);
}

