// 异步任务管理器：提交、轮询、下载、持久化、重启续拉

import * as vscode from 'vscode';
import * as fs from 'fs';
import * as path from 'path';
import { submitGenerate, queryResult, downloadImage } from './api';
import { getConfig } from './config';
import {
  TaskInfo,
  TaskJob,
  isTransientError,
  extFromUrl,
  isImageExt,
  taskFolderName,
} from './shared';

const TASK_TIMEOUT_MS = 10 * 60 * 1000; // 10 分钟
const POLL_INTERVAL_MS = 4_000;
const TASKS_KEY = 'activeTasks';

let pollingTimer: ReturnType<typeof setInterval> | null = null;
let polling = false;
let tasks: TaskInfo[] = [];
let globalState: vscode.Memento;
let secrets: vscode.SecretStorage;
let onUpdate: (() => void) | null = null;
let onTaskCompleted: ((task: TaskInfo) => void) | null = null;
let sessionStartTime = 0;

export function initTaskManager(
  ctx: vscode.ExtensionContext,
  updateCb: () => void,
  completedCb: (task: TaskInfo) => void,
): void {
  globalState = ctx.globalState;
  secrets = ctx.secrets;
  onUpdate = updateCb;
  onTaskCompleted = completedCb;
  sessionStartTime = Date.now();
  resume();
}

export function disposeTaskManager(): void {
  stopPolling();
}

export function getTasks(): TaskInfo[] {
  return tasks;
}

/** 创建新任务 */
export async function createTask(
  mdFilePath: string,
  model: string,
  concurrency: number,
): Promise<TaskInfo> {
  const config = await getConfig(secrets, globalState);
  if (!config.apiKey) {
    throw new Error('请先配置 API Key（前往设置页填写）');
  }

  const mdDir = path.dirname(mdFilePath);
  const mdFileName = path.basename(mdFilePath, '.md');
  const folderName = taskFolderName();
  const folderPath = path.join(mdDir, folderName);
  fs.mkdirSync(folderPath, { recursive: true });

  const now = Date.now();
  const task: TaskInfo = {
    folderName,
    folderPath,
    model,
    mdFileName,
    mdFilePath,
    jobs: [],
    submittedAt: now,
    startedAt: now,
  };

  for (let i = 0; i < concurrency; i++) {
    task.jobs.push({
      index: i,
      status: 'submitting',
      progress: 0,
    });
  }

  tasks.unshift(task);
  persist();

  return task;
}

/** 更新单个 job 状态 */
export function updateJob(taskFolder: string, jobIndex: number, update: Partial<TaskJob>): void {
  const task = tasks.find(t => t.folderName === taskFolder);
  if (!task) return;
  const job = task.jobs.find(j => j.index === jobIndex);
  if (!job) return;
  Object.assign(job, update);
  persist();
}

/** 后台提交所有 job */
export async function submitAllJobs(
  task: TaskInfo,
  prompt: string,
  images: string[],
  aspectRatio: string,
  imageSize: string,
): Promise<void> {
  const config = await getConfig(secrets, globalState);

  const submitOne = async (job: TaskJob) => {
    try {
      const resp = await submitGenerate(
        config.baseUrl,
        config.apiKey,
        task.model,
        prompt,
        images,
        aspectRatio,
        imageSize,
      );
      updateJob(task.folderName, job.index, {
        status: 'running',
        id: resp.id,
        progress: resp.progress ?? 0,
      });
    } catch (err) {
      updateJob(task.folderName, job.index, {
        status: 'failed',
        error: String(err),
        progress: 0,
      });
    }
  };

  // 并发提交全部 job
  await Promise.all(task.jobs.map(j => submitOne(j)));

  const allFailed = task.jobs.every(j => j.status === 'failed' || j.status === 'violation');
  const t = tasks.find(tt => tt.folderName === task.folderName);
  if (allFailed && t) {
    const errors = [...new Set(t.jobs.map(j => j.error).filter(Boolean))];
    tasks = tasks.filter(tt => tt.folderName !== task.folderName);
    // 删除空文件夹
    try { fs.rmdirSync(task.folderPath); } catch { /* 忽略 */ }
    persist();
    onUpdate?.();
    throw new Error(`全部提交失败：\n${errors.join('\n')}`);
  }

  // 启动轮询
  startPolling();
  persist();
  onUpdate?.();
}

/** 启动全局轮询定时器 */
function startPolling(): void {
  if (pollingTimer) return;
  pollingTimer = setInterval(pollAllTasks, POLL_INTERVAL_MS);
  // 立即拉一次
  pollAllTasks();
}

function stopPolling(): void {
  if (pollingTimer) {
    clearInterval(pollingTimer);
    pollingTimer = null;
  }
}

let globalImageCounter = 0;

/** 轮询所有进行中的 job */
async function pollAllTasks(): Promise<void> {
  if (polling) return; // 重入锁
  polling = true;

  try {
    const config = await getConfig(secrets, globalState);
    let hasRunning = false;

    for (const task of tasks) {
      for (const job of task.jobs) {
        if (job.status !== 'running' || !job.id) continue;
        hasRunning = true;

        try {
          const result = await queryResult(config.baseUrl, config.apiKey, job.id);
          if (result.status === 'succeeded' && result.results) {
            // 下载图片
            const downloaded: string[] = [];
            for (const r of result.results) {
              globalImageCounter++;
              const ext = extFromUrl(r.url);
              const safeExt = isImageExt(ext) ? ext : 'png';
              const fileName = `${task.mdFileName}-${globalImageCounter}.${safeExt}`;
              const destPath = path.join(task.folderPath, fileName);
              await downloadImage(r.url, destPath);
              downloaded.push(destPath);
            }
            updateJob(task.folderName, job.index, {
              status: 'succeeded',
              progress: 100,
              results: downloaded,
            });
          } else if (result.status === 'failed' || result.status === 'violation') {
            updateJob(task.folderName, job.index, {
              status: result.status,
              progress: 0,
              error: result.error ?? result.status,
            });
          } else if (result.status === 'running') {
            updateJob(task.folderName, job.index, {
              progress: result.progress ?? job.progress,
            });
          }
        } catch (err) {
          if (isTransientError(err)) {
            // 瞬时错误，保持 running，下轮重试
            continue;
          }
          updateJob(task.folderName, job.index, {
            status: 'failed',
            progress: 0,
            error: String(err),
          });
        }
      }

      // 超时兜底
      const elapsed = Date.now() - Math.max(task.startedAt, sessionStartTime);
      if (elapsed > TASK_TIMEOUT_MS) {
        for (const job of task.jobs) {
          if (job.status === 'running' || job.status === 'submitting') {
            updateJob(task.folderName, job.index, {
              status: 'failed',
              error: '任务超时（10 分钟）',
              progress: 0,
            });
          }
        }
      }

      // 检查任务是否全部终结
      checkTaskDone(task);
    }

    if (!hasRunning) {
      stopPolling();
    }
  } finally {
    polling = false;
    onUpdate?.();
  }
}

/** 检查任务是否全部终结并处理 */
function checkTaskDone(task: TaskInfo): void {
  const allDone = task.jobs.every(
    j => j.status === 'succeeded' || j.status === 'failed' || j.status === 'violation',
  );
  if (!allDone) return;

  const successCount = task.jobs.filter(j => j.status === 'succeeded').length;
  const failCount = task.jobs.filter(j => j.status === 'failed' || j.status === 'violation').length;
  const totalImages = task.jobs.reduce((acc, j) => acc + (j.results?.length ?? 0), 0);

  // 通知前端任务完成（先把完成图并入历史）
  onTaskCompleted?.(task);

  // 从列表移除
  tasks = tasks.filter(t => t.folderName !== task.folderName);

  // 无成图则删空文件夹
  if (totalImages === 0) {
    try { fs.rmdirSync(task.folderPath); } catch { /* 忽略 */ }
  }

  persist();

  // 弹通知
  if (failCount > 0) {
    const errors = [...new Set(task.jobs.filter(j => j.error).map(j => j.error))];
    const errMsg = errors.join('\n');
    if (totalImages > 0) {
      vscode.window.showWarningMessage(`任务 ${task.folderName} 部分失败（${successCount}/${task.jobs.length} 成功）：${errMsg}`);
    } else {
      vscode.window.showErrorMessage(`任务 ${task.folderName} 全部失败：${errMsg}`);
    }
  }
}

/** 持久化到 globalState */
function persist(): void {
  globalState.update(TASKS_KEY, tasks);
}

/** 重启续拉 */
function resume(): void {
  const saved = globalState.get<TaskInfo[]>(TASKS_KEY);
  if (!saved || saved.length === 0) return;

  tasks = saved;

  // submitting 态无 id 的直接判失败
  for (const task of tasks) {
    for (const job of task.jobs) {
      if (job.status === 'submitting' && !job.id) {
        job.status = 'failed';
        job.error = '提交未完成';
      }
      // 重置 progress 为 0 防止陈旧值
      if (job.status === 'running') {
        job.progress = 0;
      }
    }
    // 检查已完成
    checkTaskDone(task);
  }

  persist();

  // 如果有 running 的 job，启动轮询
  const hasRunning = tasks.some(t => t.jobs.some(j => j.status === 'running' && j.id));
  if (hasRunning) {
    startPolling();
  }

  onUpdate?.();
}

// 预览请求：与真实提交共用请求体构造，但不调 API

import * as vscode from 'vscode';
import * as path from 'path';
import * as fs from 'fs';
import { parseMarkdown, buildFinalPrompt } from './markdownParser';
import { isNanoBanana, isGptImage2Vip } from './config';
import { getConfig } from './config';
import { vipPixelSize } from './shared';

export async function showPreview(
  mdFilePath: string,
  context: vscode.ExtensionContext,
  globalState: vscode.Memento,
  secrets: vscode.SecretStorage,
): Promise<void> {
  const config = await getConfig(secrets, globalState);
  const mdDir = path.dirname(mdFilePath);
  const mdContent = fs.readFileSync(mdFilePath, 'utf-8');

  if (mdContent.trim() === '') {
    vscode.window.showErrorMessage('内容为空');
    return;
  }

  const parsed = parseMarkdown(mdContent, mdDir);
  const injection = config.modelInjections[config.model] ?? '';
  const imagesMdContent = readImagesMd();

  const finalPrompt = buildFinalPrompt(parsed.body, injection, imagesMdContent);

  // 构建请求体（仅展示用）
  const requestBody: Record<string, unknown> = {
    model: config.model,
    images: parsed.images,
    replyType: 'async',
  };

  if (isNanoBanana(config.model)) {
    requestBody.aspectRatio = config.aspectRatio;
    requestBody.imageSize = config.imageSize;
  } else if (isGptImage2Vip(config.model)) {
    requestBody.aspectRatio = vipPixelSize(config.aspectRatio, config.imageSize);
  } else {
    requestBody.aspectRatio = config.aspectRatio;
  }

  const requestUrl = `${config.baseUrl}/v1/api/generate`;

  // 剔除 prompt 和 images 的请求参数
  const paramsWithoutPrompt: Record<string, unknown> = { ...requestBody };
  delete paramsWithoutPrompt.images;
  const paramsJson = JSON.stringify(paramsWithoutPrompt, null, 2);

  // 参考图概览
  let imagesSummary: string;
  if (parsed.images.length === 0) {
    imagesSummary = '（无参考图）';
  } else {
    imagesSummary = parsed.images
      .map((uri, i) => {
        const preview = uri.slice(0, 48);
        return `image${i + 1}: ${preview}…（总长度 ${uri.length}）`;
      })
      .join('\n');
  }

  const previewContent = [
    `# 预览请求 — ${path.basename(mdFilePath)}`,
    '',
    '## 最终提示词',
    '',
    finalPrompt || '（空）',
    '',
    '## 请求地址',
    '',
    `POST ${requestUrl}`,
    '',
    '## 请求参数（已剔除 prompt 与 images 字段）',
    '',
    '```json',
    paramsJson,
    '```',
    '',
    '## 参考图概览',
    '',
    imagesSummary,
  ].join('\n');

  const doc = await vscode.workspace.openTextDocument({
    content: previewContent,
    language: 'markdown',
  });
  await vscode.window.showTextDocument(doc, { preview: true });
}

/** 读取工作区根 IMAGES.md 全文 */
export function readImagesMd(): string | null {
  const folders = vscode.workspace.workspaceFolders;
  if (!folders || folders.length === 0) return null;
  const root = folders[0].uri.fsPath;
  const imagesMdPath = path.join(root, 'IMAGES.md');
  try {
    const content = fs.readFileSync(imagesMdPath, 'utf-8');
    return content.trim() || null;
  } catch {
    return null;
  }
}

// 素材库：手动素材库 + 自动「当前路径」库

import * as vscode from 'vscode';
import * as fs from 'fs';
import * as path from 'path';
import { isImageExt } from './shared';
import { getMediaFolders } from './config';

export interface MediaFolder {
  name: string;
  path: string;
  images: string[];
}

const RECURSION_MAX_DEPTH = 3;
const RECURSION_MAX_ITEMS = 500;

/** 递归扫描图片（深度限制、条数限制） */
function scanImages(dir: string, maxDepth: number, maxItems: number, currentDepth = 0): string[] {
  const images: string[] = [];
  if (currentDepth > maxDepth || images.length >= maxItems) return images;

  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      if (images.length >= maxItems) break;
      if (entry.isDirectory() && currentDepth < maxDepth) {
        images.push(...scanImages(path.join(dir, entry.name), maxDepth, maxItems, currentDepth + 1));
      } else if (entry.isFile()) {
        const ext = path.extname(entry.name).slice(1);
        if (isImageExt(ext)) {
          images.push(path.join(dir, entry.name));
        }
      }
    }
  } catch {
    // 忽略不可读的目录
  }
  return images.slice(0, maxItems);
}

/** 扫描手动素材库 */
export function scanManualMediaFolders(workspaceState: vscode.Memento): MediaFolder[] {
  const folders = getMediaFolders(workspaceState);
  return folders.map(f => ({
    name: path.basename(f),
    path: f,
    images: scanImages(f, RECURSION_MAX_DEPTH, RECURSION_MAX_ITEMS),
  }));
}

/** 自动素材库：按生效 MD 的路径逐层生成 */
export function scanAutoMediaFolders(mdFilePath: string | null): MediaFolder[] {
  if (!mdFilePath) return [];

  const folders = vscode.workspace.workspaceFolders;
  if (!folders || folders.length === 0) return [];

  const wsRoot = folders[0].uri.fsPath;
  const mdDir = path.dirname(mdFilePath);

  // MD 不在工作区内
  if (!mdDir.startsWith(wsRoot)) return [];

  // 从工作区根的下一层到 MD 所在目录，逐层
  const result: MediaFolder[] = [];
  let current = mdDir;

  while (current.length > wsRoot.length) {
    const name = path.relative(wsRoot, current);
    try {
      const entries = fs.readdirSync(current, { withFileTypes: true });
      const images = entries
        .filter(e => e.isFile() && isImageExt(path.extname(e.name).slice(1)))
        .map(e => path.join(current, e.name));
      if (images.length > 0) {
        result.unshift({ name: name || path.basename(current), path: current, images });
      }
    } catch {
      // 忽略
    }
    current = path.dirname(current);
  }

  return result;
}

/** 获取图片路径的正则，用于扫描目录下的直接图片文件 */
export function scanHistoryImages(folderPath: string): string[] {
  const images: string[] = [];
  try {
    const entries = fs.readdirSync(folderPath, { withFileTypes: true });
    for (const entry of entries) {
      if (entry.isFile() && isImageExt(path.extname(entry.name).slice(1))) {
        images.push(path.join(folderPath, entry.name));
      }
    }
  } catch {
    // 忽略
  }
  return images;
}

/** 生成相对引用路径（POSIX 风格，含空格/括号时用尖括号包裹） */
export function makeRelativeImageRef(mdDir: string, imageAbsPath: string): string {
  let rel = path.relative(mdDir, imageAbsPath);
  // 跨盘符检查
  if (path.isAbsolute(rel) && !rel.startsWith('.')) {
    throw new Error('无法跨盘符引用');
  }
  // 转 POSIX 风格
  rel = rel.split(path.sep).join('/');
  const needsBracket = /[\s()]/.test(rel);
  if (needsBracket) {
    rel = `<${rel}>`;
  }
  if (!rel.startsWith('.') && !rel.startsWith('<')) {
    rel = './' + rel;
  }
  const baseName = path.basename(imageAbsPath, path.extname(imageAbsPath));
  return `![${baseName}](${rel})`;
}

