          }
          const mdDir = path.dirname(editor.document.fileName);
          try {
            const ref = makeRelativeImageRef(mdDir, msg.imagePath);
            editor.edit((eb) => {
              eb.insert(editor.selection.active, ref);
            });
          } catch (e) {
            vscode.window.showWarningMessage(String(e));
          }
          break;
        }

        case 'openImage': {
          const doc = await vscode.workspace.openTextDocument(vscode.Uri.file(msg.imagePath));
          await vscode.window.showTextDocument(doc);
          break;
        }

        case 'openUrl':
          await vscode.env.openExternal(vscode.Uri.parse(msg.url));
