  }

  // ---- 向前端发送消息 ----

  private postMessage(msg: ExtToWv): void {
    this.view?.webview.postMessage(msg);
  }

  async sendInit(): Promise<void> {
    const config = await getConfig(this.context.secrets, this.context.globalState);
