    });
  }

  sendTasks(): void {
    this.postMessage({ type: 'taskUpdate', tasks: getTasks() });
  }

  sendConfig(): void {
    getConfig(this.context.secrets, this.context.globalState).then((config) => {
      this.postMessage({ type: 'initResponse', config, activeMd: activeMdPath ? { filePath: activeMdPath, fileName: activeMdFileName! } : null, tasks: getTasks(), history: this.getHistory(), mediaFolders: scanManualMediaFolders(this.context.workspaceState), autoMediaFolders: scanAutoMediaFolders(activeMdPath) });
    });
  }

  sendActiveMd(): void {
    const activeMd: ActiveMdInfo | null = activeMdPath ? { filePath: activeMdPath, fileName: activeMdFileName! } : null;
    this.postMessage({ type: 'activeMdChanged', activeMd });
  }

  sendMediaFolders(): void {
    const mediaFolders = scanManualMediaFolders(this.context.workspaceState);
    const autoMediaFolders = scanAutoMediaFolders(activeMdPath);
    this.postMessage({ type: 'mediaFoldersUpdate', folders: mediaFolders });
    this.postMessage({ type: 'autoMediaFoldersUpdate', folders: autoMediaFolders });
  }

  switchToTasks(): void {
    this.postMessage({ type: 'switchTab', tab: 'tasks' });
  }

  onTaskCompleted(task: TaskInfo): void {
    this.postMessage({ type: 'taskCompleted', taskInfo: task });
    this.refreshHistory();
  }

  refreshHistory(): void {
    this.postMessage({ type: 'historyUpdate', history: this.getHistory() });
  }

  refreshAutoMedia(): void {
    this.sendMediaFolders();
  }

  private getHistory(): HistoryItem[] {
    if (!activeMdPath) return [];
    const mdDir = path.dirname(activeMdPath);
    const activeTasks = new Set(getTasks().map(t => t.folderName));

    const historyItems: HistoryItem[] = [];
    try {
      const entries = fs.readdirSync(mdDir, { withFileTypes: true });
      for (const entry of entries) {
        if (!entry.isDirectory() || !isTaskFolder(entry.name)) continue;
        if (activeTasks.has(entry.name)) continue; // 排除进行中任务
