// VS Code 扩展测试运行器

import * as path from 'path';
import { runTests } from '@vscode/test-electron';

async function main(): Promise<void> {
  try {
    const extensionDevelopmentPath = path.resolve(__dirname, '../../');
    const extensionTestsPath = path.resolve(__dirname, './suite/index');

    await runTests({
      extensionDevelopmentPath,
      extensionTestsPath,
      launchArgs: ['--disable-extensions'],
    });
  } catch (err) {
    console.error('测试运行失败:', err);
    process.exit(1);
  }
}

main();

// 测试套件入口

import * as path from 'path';
import * as Mocha from 'mocha';
import * as glob from 'glob';

export function run(): Promise<void> {
  const mocha = new Mocha({ ui: 'tdd', color: true, timeout: 10000 });

  const testsRoot = path.resolve(__dirname);

  return new Promise((resolve, reject) => {
    glob('**/**.test.js', { cwd: testsRoot }, (err: Error | null, files: string[]) => {
      if (err) return reject(err);

      for (const f of files) {
        mocha.addFile(path.resolve(testsRoot, f));
      }

      try {
        mocha.run((failures: number) => {
          if (failures > 0) reject(new Error(`${failures} tests failed.`));
          else resolve();
        });
      } catch (err) {
        reject(err);
      }
    });
  });
}

// 图片语法解析与替换测试

import * as assert from 'assert';
import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { parseMarkdown } from '../../markdownParser';

suite('markdownParser', () => {
  let tmpDir: string;

  setup(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'image-flow-test-'));
  });

  teardown(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
  });

  function createImage(name: string): string {
    // 创建一个 1x1 PNG 的最小有效文件
    const png = Buffer.from('iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR42mP8/5+hHgAHggJ/PchI7wAAAABJRU5ErkJggg==', 'base64');
    const p = path.join(tmpDir, name);
    fs.writeFileSync(p, png);
    return p;
  }

  test('普通图片路径解析', () => {
    createImage('test.png');
    const result = parseMarkdown('Hello ![alt](test.png) world', tmpDir);
    assert.strictEqual(result.images.length, 1);
    assert.ok(result.images[0].startsWith('data:image/png;base64,'));
    assert.ok(result.body.includes('[image1]'));
  });

  test('尖括号路径（含空格）', () => {
    createImage('my image.png');
    const result = parseMarkdown('Look ![pic](<my image.png>) here', tmpDir);
    assert.strictEqual(result.images.length, 1);
    assert.ok(result.images[0].startsWith('data:image/png;base64,'));
  });

  test('尖括号路径（含括号）', () => {
    createImage('pic(1).png');
    const result = parseMarkdown('See ![x](<pic(1).png>)', tmpDir);
    assert.strictEqual(result.images.length, 1);
  });

  test('重复引用复用编号', () => {
    createImage('a.png');
    const result = parseMarkdown('![1](a.png) and ![2](a.png)', tmpDir);
    assert.strictEqual(result.images.length, 1);
    assert.strictEqual(result.imageMap.get('a.png'), 1);
    // 两处都应替换为 image1
    const matches = result.body.match(/\[image1\]/g);
    assert.strictEqual(matches?.length, 2);
  });

  test('多个不同图片编号递增', () => {
    createImage('a.png');
    createImage('b.png');
    const result = parseMarkdown('![1](a.png) ![2](b.png)', tmpDir);
    assert.strictEqual(result.images.length, 2);
    assert.strictEqual(result.imageMap.get('a.png'), 1);
    assert.strictEqual(result.imageMap.get('b.png'), 2);
  });

  test('编号与参考图数组顺序一致', () => {
    createImage('first.png');
    createImage('second.png');
    createImage('third.png');
    const result = parseMarkdown('![a](first.png) ![b](second.png) ![c](third.png)', tmpDir);
    assert.strictEqual(result.images.length, 3);
    assert.ok(result.body.includes('[image1]'));
    assert.ok(result.body.includes('[image2]'));
    assert.ok(result.body.includes('[image3]'));
    // body 中 image1 在 image2 之前
    const i1 = result.body.indexOf('[image1]');
    const i2 = result.body.indexOf('[image2]');
    const i3 = result.body.indexOf('[image3]');
    assert.ok(i1 < i2);
    assert.ok(i2 < i3);
  });

  test('参考图读取失败抛出错误', () => {
    assert.throws(() => {
      parseMarkdown('![x](nonexistent.png)', tmpDir);
    }, /参考图读取失败/);
  });

  test('无图片的正文原样保留', () => {
    const result = parseMarkdown('Hello world', tmpDir);
    assert.strictEqual(result.images.length, 0);
    assert.strictEqual(result.body, 'Hello world');
  });
});

// 聚合进度计算测试

import * as assert from 'assert';
import { aggregateProgress, TaskJob } from '../../shared';

suite('aggregateProgress', () => {
  test('全 submitting 为 0', () => {
    const jobs: TaskJob[] = [
      { index: 0, status: 'submitting', progress: 0 },
      { index: 1, status: 'submitting', progress: 0 },
    ];
    assert.strictEqual(aggregateProgress(jobs), 0);
  });

  test('混合态正确计算', () => {
    const jobs: TaskJob[] = [
      { index: 0, status: 'succeeded', progress: 100 },
      { index: 1, status: 'running', progress: 50 },
      { index: 2, status: 'submitting', progress: 0 },
      { index: 3, status: 'failed', progress: 0 },
    ];
    // (100 + 50 + 0 + 100) / 4 = 62.5 → 63
    const p = aggregateProgress(jobs);
    assert.ok(p >= 62 && p <= 63);
  });

  test('全部终结为 100', () => {
    const jobs: TaskJob[] = [
      { index: 0, status: 'succeeded', progress: 100 },
      { index: 1, status: 'failed', progress: 0 },
      { index: 2, status: 'violation', progress: 0 },
    ];
    assert.strictEqual(aggregateProgress(jobs), 100);
  });

  test('空 job 列表为 0', () => {
    assert.strictEqual(aggregateProgress([]), 0);
  });
});

// 瞬时错误判定测试

import * as assert from 'assert';
import { isTransientError } from '../../shared';

suite('isTransientError', () => {
  test('HTTP 5xx 是瞬时错误', () => {
    assert.strictEqual(isTransientError('HTTP 500: Internal Server Error'), true);
    assert.strictEqual(isTransientError('HTTP 502'), true);
    assert.strictEqual(isTransientError('HTTP 503 Service Unavailable'), true);
  });

  test('HTTP 429 是瞬时错误', () => {
    assert.strictEqual(isTransientError('HTTP 429: Too Many Requests'), true);
  });

  test('abort 是瞬时错误', () => {
    assert.strictEqual(isTransientError('AbortError: The operation was aborted'), true);
    assert.strictEqual(isTransientError('fetch aborted'), true);
  });

  test('fetch failed 是瞬时错误', () => {
    assert.strictEqual(isTransientError('fetch failed'), true);
    assert.strictEqual(isTransientError('TypeError: fetch failed'), true);
  });

  test('timeout 是瞬时错误', () => {
    assert.strictEqual(isTransientError('timeout of 30000ms exceeded'), true);
  });

  test('格式错误非瞬时', () => {
    assert.strictEqual(isTransientError('无效的 API 响应（非对象）'), false);
  });

  test('HTTP 400 非瞬时', () => {
    assert.strictEqual(isTransientError('HTTP 400: Bad Request'), false);
  });

  test('普通字符串非瞬时', () => {
    assert.strictEqual(isTransientError('some random error'), false);
  });
});

