400	        if (activeTasks.has(entry.name)) continue; // 排除进行中任务
401	        const folderPath = path.join(mdDir, entry.name);
402	        const images = scanHistoryImages(folderPath);
403	        if (images.length === 0) continue;
404	        historyItems.push({
405	          folderName: entry.name,
406	          folderPath,
407	          images,
408	          imageCount: images.length,
409	        });
410	      }
411	    } catch {
412	      // 忽略
413	    }
414	
